export interface Track {
  id: string;
  title: string;
  artist: string;
  bpm: number;
  key: string;
  genre: string;
  energy: number; // 1-10
  url: string; // Blob URL or placeholder
  coverUrl?: string;
  duration: number;
}

export interface DeckState {
  track: Track | null;
  isPlaying: boolean;
  volume: number;
  speed: number;
  currentTime: number;
